// Pass through input with mode extracted
const input = $input.first().json;
const mode = (input.mode || 'calibrate').toLowerCase().trim();
return [{ json: { ...input, mode } }];

function parseCSV(csvData) {
  if (!csvData || !csvData.trim()) return [];
  function parseLine(line) { const v=[]; let q=false,c=''; for(let i=0;i<line.length;i++){const ch=line[i]; if(ch==='"'){q=!q;continue;} if(ch===','&&!q){v.push(c.trim());c='';continue;} c+=ch;} v.push(c.trim()); return v; }
  const lines = csvData.trim().split('\n');
  const h = parseLine(lines[0]);
  const rows = [];
  for (let i=1; i<lines.length; i++) { const v=parseLine(lines[i]); if(v.length<2)continue; const r={}; h.forEach((hh,idx)=>r[hh]=v[idx]||''); rows.push(r); }
  return rows;
}
const n = s => { const x=Number(String(s||'0').replace(/[,$]/g,'')); return isFinite(x)?x:0; };

const input = $('Route Mode').first().json;

// Parse opportunity lists to get unique account names
const wonOpps = parseCSV($('Fetch Won Opps').first().json.data || '');
const lostOpps = parseCSV($('Fetch Lost Opps').first().json.data || '');
const accountMetrics = parseCSV($('Fetch Account Metrics').first().json.data || '');

// Extract unique account names from won/lost opps
const wonAccounts = new Set();
wonOpps.forEach(o => {
  const acct = o['Opportunity Account (name)'] || o['Account (name)'] || '';
  if (acct) wonAccounts.add(acct.toLowerCase());
});

const lostAccounts = new Set();
lostOpps.forEach(o => {
  const acct = o['Opportunity Account (name)'] || o['Account (name)'] || '';
  if (acct) lostAccounts.add(acct.toLowerCase());
});

// Remove accounts that appear in both (mixed results)
const pureWon = new Set([...wonAccounts].filter(a => !lostAccounts.has(a)));
const pureLost = new Set([...lostAccounts].filter(a => !wonAccounts.has(a)));

// Build metrics lookup by account name
const metricsMap = {};
accountMetrics.forEach(a => {
  const name = (a['Account Name'] || '').toLowerCase();
  if (name) metricsMap[name] = a;
});

// Match account metrics to won/lost cohorts
function getMetrics(accountSet) {
  const matched = [];
  for (const acctName of accountSet) {
    const m = metricsMap[acctName];
    if (m) matched.push(m);
  }
  return matched;
}

const winners = getMetrics(pureWon);
const losers = getMetrics(pureLost);

function analyze(accs) {
  if (!accs.length) return null;
  const vals = accs.map(a => ({
    eng: n(a['Account Engagement Level']),
    mtg90: n(a['Meetings (Last 90 Days)']),
    eS: n(a['Emails Sent (Last 90 Days)']), eR: n(a['Emails Received (Last 90 Days)']),
    ppl: n(a['People Engaged (Last 90 Days)']), execs: n(a['Executives Engaged (Last 90 Days)']),
    execActs: n(a['Activities with Executives (C-Level) (Last 90 Days)']),
    industry: a['Industry']||'Unknown', type: a['Account Type']||'Unknown'
  }));
  const avg = fn => Math.round(vals.reduce((s,a)=>s+fn(a),0)/vals.length*10)/10;
  const pct = fn => Math.round(vals.reduce((s,a)=>s+fn(a),0)/vals.length*100);
  const indMap = {};
  vals.forEach(v => { indMap[v.industry] = (indMap[v.industry]||0)+1; });
  const topInd = Object.entries(indMap).sort((a,b)=>b[1]-a[1]).slice(0,5)
    .map(([ind,ct]) => ind+' ('+Math.round(ct/vals.length*100)+'%)');
  const typeMap = {};
  vals.forEach(v => { typeMap[v.type] = (typeMap[v.type]||0)+1; });
  const topTypes = Object.entries(typeMap).sort((a,b)=>b[1]-a[1]).slice(0,3)
    .map(([t,ct]) => t+' ('+Math.round(ct/vals.length*100)+'%)');
  return {
    count: accs.length, oppCount: 0,
    eng: avg(a=>a.eng), mtg90: avg(a=>a.mtg90),
    emails: avg(a=>a.eS+a.eR), emailsSent: avg(a=>a.eS), emailsRecv: avg(a=>a.eR),
    ppl: avg(a=>a.ppl), execs: avg(a=>a.execs), execActs: avg(a=>a.execActs),
    mtgRatio: pct(a => { const t=a.mtg90+a.eS+a.eR; return t>0?a.mtg90/t:0; }),
    execPct: pct(a => a.ppl>0 ? Math.min(a.execs/a.ppl, 1) : 0),
    respRate: Math.round(vals.reduce((s,a)=>s+(a.eS>0?a.eR/a.eS:0),0)/vals.length*100)/100,
    topInd, topTypes
  };
}

const w = analyze(winners);
const l = analyze(losers);
if (!w || !l) {
  return [{json:{
    channel: input.channelId,
    text: 'Insufficient data for ICP calibration. Need accounts with both won and lost opps in last 90 days.',
    username: input.assistantName || 'Aria',
    icon_emoji: input.assistantEmoji || ':robot_face:',
  }}];
}
w.oppCount = wonOpps.length;
l.oppCount = lostOpps.length;

const gap = (wv,lv,s) => { const d=Math.round((wv-lv)*10)/10; return (d>0?'+':'')+d+(s||''); };
