  '*:bar_chart: Behavioral Benchmarks*\n```\n'+
  'Dimension         | Winners | Losers  | Gap\n'+
  '------------------+---------+---------+---------\n'+
  'Engagement        | '+String(w.eng).padEnd(7)+' | '+String(l.eng).padEnd(7)+' | '+gap(w.eng,l.eng)+'\n'+
  'Meetings (90d)    | '+String(w.mtg90).padEnd(7)+' | '+String(l.mtg90).padEnd(7)+' | '+gap(w.mtg90,l.mtg90)+'\n'+
  'Emails Sent       | '+String(w.emailsSent).padEnd(7)+' | '+String(l.emailsSent).padEnd(7)+' | '+gap(w.emailsSent,l.emailsSent)+'\n'+
  'Emails Received   | '+String(w.emailsRecv).padEnd(7)+' | '+String(l.emailsRecv).padEnd(7)+' | '+gap(w.emailsRecv,l.emailsRecv)+'\n'+
  'People Engaged    | '+String(w.ppl).padEnd(7)+' | '+String(l.ppl).padEnd(7)+' | '+gap(w.ppl,l.ppl)+'\n'+
  'Execs Engaged     | '+String(w.execs).padEnd(7)+' | '+String(l.execs).padEnd(7)+' | '+gap(w.execs,l.execs)+'\n'+
  'Exec Activities   | '+String(w.execActs).padEnd(7)+' | '+String(l.execActs).padEnd(7)+' | '+gap(w.execActs,l.execActs)+'\n'+
  'Meeting Ratio     | '+String(w.mtgRatio+'%').padEnd(7)+' | '+String(l.mtgRatio+'%').padEnd(7)+' | '+gap(w.mtgRatio,l.mtgRatio,'%')+'\n'+
  'Exec % of People  | '+String(w.execPct+'%').padEnd(7)+' | '+String(l.execPct+'%').padEnd(7)+' | '+gap(w.execPct,l.execPct,'%')+'\n'+
  'Email Response    | '+String(w.respRate).padEnd(7)+' | '+String(l.respRate).padEnd(7)+' | '+gap(w.respRate,l.respRate)+'\n'+
  '```\n\n'+
  '*:trophy: Winner Profile*\n'+
  '\u2022 Industries: '+w.topInd.join(', ')+'\n'+
  '\u2022 Account types: '+w.topTypes.join(', ')+'\n'+
  '\u2022 '+w.mtg90+' meetings/90d, '+w.mtgRatio+'% meeting ratio\n'+
  '\u2022 '+w.ppl+' people engaged, '+w.execs+' execs, '+w.execPct+'% exec coverage\n'+
  '\u2022 '+w.respRate+' email response rate ('+w.emailsRecv+' received / '+w.emailsSent+' sent)\n\n'+
  '*:no_entry_sign: Loser Profile*\n'+
  '\u2022 Industries: '+l.topInd.join(', ')+'\n'+
  '\u2022 Account types: '+l.topTypes.join(', ')+'\n'+
  '\u2022 '+l.mtg90+' meetings/90d, '+l.mtgRatio+'% meeting ratio\n'+
  '\u2022 '+l.ppl+' people engaged, '+l.execs+' execs, '+l.execPct+'% exec coverage\n'+
  '\u2022 '+l.respRate+' email response rate\n\n'+
  '*:dart: Key Differentiators* (biggest gaps)\n';

const dims = [
  {name:'Engagement', gap:Math.abs(w.eng-l.eng), desc: w.eng+' vs '+l.eng},
  {name:'Meetings (90d)', gap:Math.abs(w.mtg90-l.mtg90), desc: w.mtg90+' vs '+l.mtg90},
  {name:'Emails Total', gap:Math.abs(w.emails-l.emails), desc: w.emails+' vs '+l.emails},
  {name:'People Engaged', gap:Math.abs(w.ppl-l.ppl), desc: w.ppl+' vs '+l.ppl},
  {name:'Execs Engaged', gap:Math.abs(w.execs-l.execs), desc: w.execs+' vs '+l.execs},
  {name:'Exec Activities', gap:Math.abs(w.execActs-l.execActs), desc: w.execActs+' vs '+l.execActs},
  {name:'Meeting Ratio', gap:Math.abs(w.mtgRatio-l.mtgRatio), desc: w.mtgRatio+'% vs '+l.mtgRatio+'%'},
  {name:'Email Response', gap:Math.abs(w.respRate-l.respRate), desc: w.respRate+' vs '+l.respRate}
].sort((a,b) => b.gap - a.gap);

text += dims.slice(0,4).map((d,i) => (i+1)+'. *'+d.name+'*: '+d.desc+' (winners vs losers)').join('\n');
text += '\n\n_Close date in last 90 days \u2022 Accounts with mixed results excluded \u2022 People.ai + Claude AI_';

return [{json:{
  channel: input.channelId,
  text: text,
  username: input.assistantName || 'Aria',
  icon_emoji: input.assistantEmoji || ':robot_face:',
}}];

